// НЕ работает на PHP 8+ (десериализация phar удалена).
// Триггерится любой файловой операцией (include, file_get_contents,
// file_exists, is_file, copy, stat, md5_file, getimagesize, ...).
class AnyClass {
    public $data = null;
    public function __construct($data) {
        $this->data = $data;
    }

    function __destruct() {
        system($this->data);
    }
}

